```class Solution {
public:
    bool reorderedPowerOf2(int n) {
        string s = to_string(n);
        sort(s.begin(), s.end());
        for (int i = 0; i < (1 << 20); i++) {
            string t = to_string(1 << (20 - __builtin_clz(i)));
            if (s == t) return true;
        }
        return false;
    }
};```
